const remoteHtmlCandidates = ["https://raw.githubusercontent.com/Youzini-afk/smyxiuxianshijiezhuangtailan/main/dist/%E4%BF%AE%E4%BB%99%E4%B8%96%E7%95%8C%E7%8A%B6%E6%80%81%E6%A0%8F/index.html","https://testingcf.jsdelivr.net/gh/Youzini-afk/smyxiuxianshijiezhuangtailan@main/dist/%E4%BF%AE%E4%BB%99%E4%B8%96%E7%95%8C%E7%8A%B6%E6%80%81%E6%A0%8F/index.html"];
const frameId = "cultivation-world-status-bar-frame";
const bridgeKey = "__cultivationWorldStatusBarBridge";
const loadingHtml = "<!DOCTYPE html>\n<html>\n<head>\n<link rel=\"stylesheet\" href=\"https://testingcf.jsdelivr.net/npm/@fortawesome/fontawesome-free/css/all.min.css\"></link>\n<script src=\"https://testingcf.jsdelivr.net/gh/n0vi028/JS-Slash-Runner/lib/tailwindcss.min.js\"></script>\n<script src=\"https://testingcf.jsdelivr.net/npm/jquery\"></script>\n<script src=\"https://testingcf.jsdelivr.net/npm/jquery-ui/dist/jquery-ui.min.js\"></script>\n<link rel=\"stylesheet\" href=\"https://testingcf.jsdelivr.net/npm/jquery-ui/themes/base/theme.min.css\" />\n<script src=\"https://testingcf.jsdelivr.net/npm/jquery-ui-touch-punch\"></script>\n<script src=\"https://testingcf.jsdelivr.net/npm/lodash\"></script>\n<script src=\"https://testingcf.jsdelivr.net/gh/n0vi028/JS-Slash-Runner/src/iframe/adjust_iframe_height.js\"></script>\n<style>\n*,*::before,*::after{box-sizing:border-box;}\nhtml,body{margin:0!important;padding:0;overflow:hidden!important;max-width:100%!important;}\n</style>\n</head>\n<body><div style=\"display:grid;place-items:center;min-height:100vh;background:#08101f;color:#f5f7fb;font-family:'Microsoft YaHei UI','PingFang SC',sans-serif;\">修仙世界状态栏加载中...</div></body></html>";
const errorHtml = message => "<!DOCTYPE html>\n<html>\n<head>\n<link rel=\"stylesheet\" href=\"https://testingcf.jsdelivr.net/npm/@fortawesome/fontawesome-free/css/all.min.css\"></link>\n<script src=\"https://testingcf.jsdelivr.net/gh/n0vi028/JS-Slash-Runner/lib/tailwindcss.min.js\"></script>\n<script src=\"https://testingcf.jsdelivr.net/npm/jquery\"></script>\n<script src=\"https://testingcf.jsdelivr.net/npm/jquery-ui/dist/jquery-ui.min.js\"></script>\n<link rel=\"stylesheet\" href=\"https://testingcf.jsdelivr.net/npm/jquery-ui/themes/base/theme.min.css\" />\n<script src=\"https://testingcf.jsdelivr.net/npm/jquery-ui-touch-punch\"></script>\n<script src=\"https://testingcf.jsdelivr.net/npm/lodash\"></script>\n<script src=\"https://testingcf.jsdelivr.net/gh/n0vi028/JS-Slash-Runner/src/iframe/adjust_iframe_height.js\"></script>\n<style>\n*,*::before,*::after{box-sizing:border-box;}\nhtml,body{margin:0!important;padding:0;overflow:hidden!important;max-width:100%!important;}\n</style>\n</head>\n<body><div style=\"padding:20px;min-height:100vh;background:#08101f;color:#f5f7fb;font-family:'Microsoft YaHei UI','PingFang SC',sans-serif;display:flex;align-items:center;justify-content:center;text-align:center;line-height:1.6;\">${message}</div></body></html>";

const parentWindow = window.parent;
const parentDocument = parentWindow.document;

parentWindow[bridgeKey] = {
  Vue: window.Vue,
  z: window.z,
  SillyTavern: window.SillyTavern,
  waitGlobalInitialized: (...args) => waitGlobalInitialized(...args),
  getVariables: (...args) => getVariables(...args),
  updateVariablesWith: (...args) => updateVariablesWith(...args),
  errorCatched: (...args) => errorCatched(...args),
};

parentDocument.getElementById(frameId)?.remove();

const iframe = parentDocument.createElement('iframe');
iframe.id = frameId;
iframe.setAttribute('script_id', typeof getScriptId === 'function' ? getScriptId() : "89e4c136-2e4e-4be8-9f71-7b3fe3a4fd91");
iframe.setAttribute('title', "修仙世界状态栏");
iframe.setAttribute('frameborder', '0');
iframe.setAttribute('allowtransparency', 'true');
iframe.style.cssText = [
  'position:fixed',
  'top:0',
  'right:0',
  'width:min(860px, 100vw)',
  'height:min(780px, 100vh)',
  'border:0',
  'background:transparent',
  'z-index:9999',
].join(';');
iframe.srcdoc = loadingHtml;
parentDocument.body.appendChild(iframe);

const notifyError = message => {
  console.error('[修仙世界状态栏]', message);
  if (typeof toastr !== 'undefined') {
    toastr.error(message, '修仙世界状态栏');
  }
};

const injectBridge = html => {
  const moduleScriptMatch = html.match(/<script type="module">([\s\S]*?)<\/script>/i);
  const styleMatch = html.match(/<style>([\s\S]*?)<\/style>/i);
  if (!moduleScriptMatch || !styleMatch) {
    throw new Error('远程页面缺少模块脚本或样式，无法挂载状态栏。');
  }

  const moduleScript = moduleScriptMatch[1].trim().replace(/<\/script>/gi, '<\\/script>');
  const styleContent = styleMatch[1].trim();
  return "<!DOCTYPE html>\n<html>\n<head>\n<link rel=\"stylesheet\" href=\"https://testingcf.jsdelivr.net/npm/@fortawesome/fontawesome-free/css/all.min.css\"></link>\n<script src=\"https://testingcf.jsdelivr.net/gh/n0vi028/JS-Slash-Runner/lib/tailwindcss.min.js\"></script>\n<script src=\"https://testingcf.jsdelivr.net/npm/jquery\"></script>\n<script src=\"https://testingcf.jsdelivr.net/npm/jquery-ui/dist/jquery-ui.min.js\"></script>\n<link rel=\"stylesheet\" href=\"https://testingcf.jsdelivr.net/npm/jquery-ui/themes/base/theme.min.css\" />\n<script src=\"https://testingcf.jsdelivr.net/npm/jquery-ui-touch-punch\"></script>\n<script src=\"https://testingcf.jsdelivr.net/npm/lodash\"></script>\n<script src=\"https://testingcf.jsdelivr.net/gh/n0vi028/JS-Slash-Runner/src/iframe/adjust_iframe_height.js\"></script>\n<style>\n*,*::before,*::after{box-sizing:border-box;}\nhtml,body{margin:0!important;padding:0;overflow:hidden!important;max-width:100%!important;}\n</style>\n</head>\n<body></body></html>"
    .replace('</head>', "<script>\n(() => {\n  const bridge = window.parent.__cultivationWorldStatusBarBridge;\n  if (!bridge) {\n    throw new Error('修仙世界状态栏桥接对象不存在。');\n  }\n\n  window.Vue = bridge.Vue;\n  window.z = bridge.z;\n  window.SillyTavern = bridge.SillyTavern;\n  window.waitGlobalInitialized = (...args) => bridge.waitGlobalInitialized(...args);\n  window.getVariables = (...args) => bridge.getVariables(...args);\n  window.updateVariablesWith = (...args) => bridge.updateVariablesWith(...args);\n  window.errorCatched = (...args) => bridge.errorCatched(...args);\n  window.getCurrentMessageId = () => 'latest';\n})();\n</script>\n<style>__STYLE__</style>\n</head>".replace('__STYLE__', styleContent))
    .replace('</body>', '<div id="app"></div><script type="module">' + moduleScript + '</script></body>');
};

const fetchRemoteHtml = async () => {
  const failures = [];
  for (const candidate of remoteHtmlCandidates) {
    try {
      const response = await fetch(candidate + '?t=' + Date.now(), { cache: 'no-store' });
      if (!response.ok) {
        failures.push(candidate + ' => HTTP ' + response.status);
        continue;
      }
      return await response.text();
    } catch (error) {
      failures.push(candidate + ' => ' + (error instanceof Error ? error.message : String(error)));
    }
  }

  throw new Error(failures.join(' | '));
};

$(window).on('pagehide', () => {
  parentDocument.getElementById(frameId)?.remove();
  delete parentWindow[bridgeKey];
});

(async () => {
  try {
    const remoteHtml = await fetchRemoteHtml();
    iframe.srcdoc = injectBridge(remoteHtml);
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    notifyError('在线加载失败：' + message);
    iframe.srcdoc = errorHtml('在线加载失败，请稍后重试。<br>' + message.replace(/</g, '&lt;').replace(/>/g, '&gt;'));
  }
})();
